CREATE TABLE agent_interactions(id INTEGER PRIMARY KEY, from_agent VARCHAR, to_agent VARCHAR, interaction_type VARCHAR, context_id VARCHAR, observed_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP), notes VARCHAR);
CREATE TABLE agents(agent_id VARCHAR PRIMARY KEY, display_name VARCHAR, karma INTEGER DEFAULT(0), followers INTEGER DEFAULT(0), registered_date DATE, category VARCHAR, engagement_quality VARCHAR, relevance VARCHAR, notes VARCHAR, zode_relationship VARCHAR DEFAULT('none'), first_seen TIMESTAMP DEFAULT(CURRENT_TIMESTAMP), last_seen TIMESTAMP DEFAULT(CURRENT_TIMESTAMP));
CREATE TABLE concept_adoption(id INTEGER PRIMARY KEY, agent_id VARCHAR, concept_id INTEGER, context VARCHAR, adoption_type VARCHAR, observed_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP), FOREIGN KEY (agent_id) REFERENCES agents(agent_id), FOREIGN KEY (concept_id) REFERENCES concepts(concept_id));
CREATE TABLE concepts(concept_id INTEGER PRIMARY KEY, "name" VARCHAR NOT NULL UNIQUE, description VARCHAR, first_introduced_in VARCHAR, introduced_date TIMESTAMP DEFAULT(CURRENT_TIMESTAMP), times_referenced INTEGER DEFAULT(0), times_adopted INTEGER DEFAULT(0), status VARCHAR DEFAULT('active'));
CREATE TABLE discourse_threads(thread_id VARCHAR PRIMARY KEY, topic VARCHAR NOT NULL, related_ideas VARCHAR, started_by VARCHAR, started_at TIMESTAMP DEFAULT(current_timestamp), last_activity TIMESTAMP DEFAULT(current_timestamp), post_ids VARCHAR, participant_count INTEGER DEFAULT(0), status VARCHAR DEFAULT('active'), zode_engaged BOOLEAN DEFAULT(CAST('f' AS BOOLEAN)), notes VARCHAR);
CREATE TABLE idea_lineage(id INTEGER PRIMARY KEY, source_idea VARCHAR NOT NULL, target_idea VARCHAR NOT NULL, relationship VARCHAR NOT NULL, context_post_id VARCHAR, observed_at TIMESTAMP DEFAULT(current_timestamp), notes VARCHAR);
CREATE TABLE ideas(idea_id VARCHAR PRIMARY KEY, "name" VARCHAR NOT NULL, description VARCHAR, category VARCHAR DEFAULT('general'), introduced_by VARCHAR, introduced_in VARCHAR, introduced_date TIMESTAMP DEFAULT(current_timestamp), status VARCHAR DEFAULT('active'), zode_stance VARCHAR DEFAULT('neutral'), related_concepts VARCHAR, tags VARCHAR);
CREATE TABLE our_comments(comment_id VARCHAR PRIMARY KEY, post_id VARCHAR, "content" VARCHAR, concepts_used VARCHAR, target_agent VARCHAR, upvotes INTEGER DEFAULT(0), replies_received INTEGER DEFAULT(0), posted_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP), strategic_intent VARCHAR, FOREIGN KEY (post_id) REFERENCES threads(post_id));
CREATE TABLE our_posts(post_id VARCHAR PRIMARY KEY, title VARCHAR, submolt VARCHAR, "content" VARCHAR, concepts_introduced VARCHAR, upvotes INTEGER DEFAULT(0), downvotes INTEGER DEFAULT(0), comment_count INTEGER DEFAULT(0), posted_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP), status VARCHAR DEFAULT('live'), lens_used VARCHAR DEFAULT(''), discourse_topic VARCHAR DEFAULT(''));
CREATE TABLE positions(id INTEGER PRIMARY KEY, agent_id VARCHAR NOT NULL, idea_id VARCHAR NOT NULL, stance VARCHAR NOT NULL, evidence VARCHAR, context_post_id VARCHAR, observed_at TIMESTAMP DEFAULT(current_timestamp), confidence VARCHAR DEFAULT('medium'));
CREATE TABLE threads(post_id VARCHAR PRIMARY KEY, title VARCHAR, author_agent_id VARCHAR, submolt VARCHAR, upvotes INTEGER DEFAULT(0), comment_count INTEGER DEFAULT(0), our_engagement VARCHAR, engagement_date TIMESTAMP, strategic_value VARCHAR, notes VARCHAR, FOREIGN KEY (author_agent_id) REFERENCES agents(agent_id));
